import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import API from '../services/axios';

function Register() {
  const navigate = useNavigate();
  const [form, setForm] = useState({ name: '', email: '', password: '', confirmPassword: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault(); setError('');
    if (form.password !== form.confirmPassword) { setError('Passwords do not match!'); return; }
    if (form.password.length < 6) { setError('Password must be at least 6 characters.'); return; }
    setLoading(true);
    try {
      const res = await API.post('/auth/signup', { name: form.name, email: form.email, password: form.password });
      localStorage.setItem('token', res.data.token);
      localStorage.setItem('user', JSON.stringify(res.data.user));
      navigate('/home');
    } catch (err) {
      setError(err.response?.data?.message || 'Registration failed. Try again.');
    } finally { setLoading(false); }
  };

  const inp = { width: '100%', padding: '12px 13px 12px 42px', background: 'white', border: '1.5px solid #f0ddd7', borderRadius: '11px', color: '#2d1f1f', fontSize: '0.88rem', outline: 'none', boxSizing: 'border-box' };

  return (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #fdf6f3 0%, #f9ede8 50%, #f5e0d8 100%)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '2rem', fontFamily: "'DM Sans', sans-serif", position: 'relative', overflow: 'hidden' }}>
      <div style={{ position: 'absolute', top: '-100px', left: '-80px', width: '380px', height: '380px', borderRadius: '50%', background: 'radial-gradient(circle, rgba(201,169,154,0.2) 0%, transparent 70%)', pointerEvents: 'none' }} />

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', maxWidth: '880px', width: '100%', borderRadius: '28px', overflow: 'hidden', boxShadow: '0 30px 80px rgba(201,169,154,0.3)', border: '1px solid #f0ddd7' }}>

        {/* Left - Form */}
        <div style={{ background: '#fffaf8', padding: '2.5rem', display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '1.5rem' }}>
            <div style={{ width: '34px', height: '34px', background: 'linear-gradient(135deg, #c9a99a, #e8c4b8)', borderRadius: '9px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1rem' }}>🌸</div>
            <span style={{ fontWeight: '700', fontSize: '1.1rem', color: '#2d1f1f', fontFamily: "'Cormorant Garamond', serif" }}>Event<span style={{ color: '#c9a99a' }}>Hub</span></span>
          </div>

          <h1 style={{ color: '#2d1f1f', fontSize: '1.7rem', fontWeight: '700', marginBottom: '0.3rem', fontFamily: "'Cormorant Garamond', serif" }}>Create Account</h1>
          <p style={{ color: '#a08880', fontSize: '0.84rem', marginBottom: '1.4rem' }}>Join our lovely community 🌷</p>

          {error && <div style={{ background: '#fdeee9', border: '1px solid #f0c4b8', color: '#a05040', padding: '11px 14px', borderRadius: '10px', marginBottom: '1.2rem', fontSize: '0.83rem' }}>⚠️ {error}</div>}

          <form onSubmit={handleSubmit}>
            {[
              { label: 'Full Name', name: 'name', type: 'text', icon: '👤', placeholder: 'Your name' },
              { label: 'Email Address', name: 'email', type: 'email', icon: '✉️', placeholder: 'you@example.com' },
              { label: 'Password', name: 'password', type: 'password', icon: '🔑', placeholder: 'Min 6 characters' },
              { label: 'Confirm Password', name: 'confirmPassword', type: 'password', icon: '✅', placeholder: 'Repeat password' },
            ].map(field => (
              <div key={field.name} style={{ marginBottom: '0.9rem' }}>
                <label style={{ display: 'block', color: '#6b5a55', fontSize: '0.76rem', fontWeight: '600', marginBottom: '6px' }}>{field.label}</label>
                <div style={{ position: 'relative' }}>
                  <span style={{ position: 'absolute', left: '13px', top: '50%', transform: 'translateY(-50%)', fontSize: '0.85rem' }}>{field.icon}</span>
                  <input type={field.type} name={field.name} value={form[field.name]}
                    onChange={e => setForm({ ...form, [e.target.name]: e.target.value })}
                    required placeholder={field.placeholder} style={inp}
                    onFocus={e => e.target.style.borderColor = '#c9a99a'}
                    onBlur={e => e.target.style.borderColor = '#f0ddd7'} />
                </div>
              </div>
            ))}
            <button type="submit" disabled={loading} style={{ width: '100%', padding: '13px', background: 'linear-gradient(135deg, #c9a99a, #b8887a)', color: 'white', border: 'none', borderRadius: '11px', fontWeight: '600', fontSize: '0.92rem', cursor: 'pointer', marginTop: '0.6rem', boxShadow: '0 6px 20px rgba(201,169,154,0.4)', opacity: loading ? 0.7 : 1, fontFamily: "'DM Sans', sans-serif" }}>
              {loading ? '✨ Creating...' : '🌸 Create Account'}
            </button>
          </form>

          <p style={{ marginTop: '1.2rem', textAlign: 'center', color: '#a08880', fontSize: '0.83rem' }}>
            Already have an account?{' '}
            <Link to="/login" style={{ color: '#c9a99a', fontWeight: '700', textDecoration: 'none' }}>Sign In →</Link>
          </p>
        </div>

        {/* Right - Promo Panel */}
        <div style={{ background: 'linear-gradient(150deg, #c9a99a 0%, #b8887a 50%, #a0706a 100%)', padding: '2.5rem', display: 'flex', flexDirection: 'column', justifyContent: 'center', position: 'relative', overflow: 'hidden' }}>
          <div style={{ position: 'absolute', top: '-50px', left: '-50px', width: '180px', height: '180px', borderRadius: '50%', background: 'rgba(255,255,255,0.1)' }} />
          <div style={{ position: 'relative' }}>
            <div style={{ fontSize: '2.5rem', marginBottom: '1rem' }}>🚀</div>
            <h2 style={{ color: 'white', fontSize: '1.8rem', fontWeight: '700', marginBottom: '0.8rem', lineHeight: '1.3', fontFamily: "'Cormorant Garamond', serif" }}>Join EventHub!</h2>
            <p style={{ color: 'rgba(255,255,255,0.75)', lineHeight: '1.7', marginBottom: '1.5rem', fontSize: '0.85rem' }}>Explore and book amazing events near you. Free forever.</p>
            {[
              { icon: '🆓', text: 'Free to join always' },
              { icon: '🔔', text: 'Event notifications' },
              { icon: '🎟️', text: 'Instant booking' },
              { icon: '💝', text: 'Exclusive deals' },
            ].map((f, i) => (
              <div key={i} style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '12px' }}>
                <div style={{ width: '32px', height: '32px', background: 'rgba(255,255,255,0.2)', borderRadius: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.85rem', flexShrink: 0 }}>{f.icon}</div>
                <span style={{ color: 'rgba(255,255,255,0.88)', fontSize: '0.82rem', fontWeight: '500' }}>{f.text}</span>
              </div>
            ))}
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px', marginTop: '1.5rem' }}>
              {[{ num: '10K+', label: 'Members' }, { num: '500+', label: 'Events' }, { num: '50K+', label: 'Tickets' }, { num: '4.9★', label: 'Rating' }].map((s, i) => (
                <div key={i} style={{ background: 'rgba(255,255,255,0.15)', borderRadius: '10px', padding: '0.8rem', textAlign: 'center' }}>
                  <p style={{ color: 'white', fontWeight: '800', fontSize: '1.1rem', margin: 0 }}>{s.num}</p>
                  <p style={{ color: 'rgba(255,255,255,0.65)', fontSize: '0.7rem', margin: 0 }}>{s.label}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
export default Register;
